// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package policy

import (
	"context"
	"encoding/json"
	"io"

	"github.com/sirupsen/logrus"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/lock"
	"github.com/cilium/cilium/pkg/logging"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

const (
	// AuditLogSubsys is the logging subsystem for audit logging
	AuditLogSubsys = "policy-audit"
)

// PolicyAuditLogger provides structured logging of policy evaluation decisions
// for audit and debugging purposes.
type PolicyAuditLogger struct {
	lock.Mutex

	// log is the logger instance used for audit logging
	log logrus.FieldLogger

	// logLevel is the minimum log level for policy audit events
	logLevel logrus.Level

	// output is an optional custom output writer for audit logs
	// If set, audit logs are written as JSON to this writer in addition to the logger
	output io.Writer
}

// NewPolicyAuditLogger creates a new PolicyAuditLogger with the specified configuration.
// If output is nil, logs are written only to the standard logger.
func NewPolicyAuditLogger(logLevel logrus.Level, output io.Writer) *PolicyAuditLogger {
	logger := logging.DefaultLogger.WithField(logfields.LogSubsys, AuditLogSubsys)
	return &PolicyAuditLogger{
		log:      logger,
		logLevel: logLevel,
		output:   output,
	}
}

// LogDecision logs a policy decision with the given parameters.
//
// Parameters:
//   - identity: the identity that the policy decision applies to
//   - policy: a string description of the policy being evaluated
//   - verdict: the result of the policy evaluation (e.g., "allow", "deny")
//   - reason: a string explaining why this verdict was reached
func (pal *PolicyAuditLogger) LogDecision(identity identity.NumericIdentity, policy, verdict, reason string) {
	pal.Lock()
	defer pal.Unlock()

	scopedLog := pal.log.WithFields(logrus.Fields{
		logfields.Identity: identity,
		"policy":           policy,
		"verdict":          verdict,
		"reason":           reason,
	})

	scopedLog.Log(pal.logLevel, "Policy decision")

	// Write to custom output if configured
	if pal.output != nil {
		auditEvent := map[string]interface{}{
			"type":     "policy_decision",
			"identity": identity,
			"policy":   policy,
			"verdict":  verdict,
			"reason":   reason,
		}
		if data, err := json.Marshal(auditEvent); err == nil {
			pal.output.Write(append(data, '\n'))
		}
	}
}

// LogEvaluation logs the result of a policy evaluation.
//
// Parameters:
//   - ctx: context for the evaluation
//   - policyKey: key identifying the policy being evaluated
//   - selectorCache: the SelectorCache used during evaluation
//   - result: the result of the policy evaluation
func (pal *PolicyAuditLogger) LogEvaluation(ctx context.Context, policyKey string, selectorCache *SelectorCache, result interface{}) {
	pal.Lock()
	defer pal.Unlock()

	scopedLog := pal.log.WithFields(logrus.Fields{
		logfields.PolicyKey: policyKey,
		"evaluation":        "complete",
	})

	scopedLog.Log(pal.logLevel, "Policy evaluation completed")

	// Write to custom output if configured
	if pal.output != nil {
		auditEvent := map[string]interface{}{
			"type":       "policy_evaluation",
			"policyKey":  policyKey,
			"result":     result,
			"hasCache":   selectorCache != nil,
		}
		if data, err := json.Marshal(auditEvent); err == nil {
			pal.output.Write(append(data, '\n'))
		}
	}
}

// SetLogLevel updates the minimum log level for policy audit events.
func (pal *PolicyAuditLogger) SetLogLevel(logLevel logrus.Level) {
	pal.Lock()
	defer pal.Unlock()
	pal.logLevel = logLevel
}

// SetOutput updates the custom output writer for audit logs.
// Pass nil to disable custom output writing.
func (pal *PolicyAuditLogger) SetOutput(output io.Writer) {
	pal.Lock()
	defer pal.Unlock()
	pal.output = output
}

